from flask import Flask, request, jsonify, current_app
from flask_login import LoginManager, UserMixin, login_user, logout_user, current_user, login_required
from werkzeug.security import generate_password_hash, check_password_hash
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY')
login_manager = LoginManager()
login_manager.init_app(app)

class User(UserMixin):
    pass

users = {}

@login_manager.user_loader
def load_user(user_id):
    return users.get(user_id)

@app.route('/api/profile', methods=['POST'])
@login_required
def update_profile():
    data = request.get_json()
    if 'email' in data:
        users[current_user.id]['email'] = data['email']
    if 'password' in data:
        hashed_password = generate_password_hash(data['password'])
        users[current_user.id]['password'] = hashed_password
    if 'two_factor_auth_enabled' in data:
        users[current_user.id]['two_factor_auth_enabled'] = bool(data['two_factor_auth_enabled'])
    return jsonify({'message': 'Profile updated successfully.'})

@app.route('/api/login', methods=['POST'])
def login():
    data = request.get_json()
    user = User(id=1)  # Assuming a user with id 1 exists for simplicity
    if check_password_hash(users[user.id]['password'], data['password']):
        login_user(user)
        return jsonify({'message': 'Logged in successfully.'})
    else:
        return jsonify({'error': 'Invalid credentials.'})

@app.route('/api/logout')
@login_required
def logout():
    logout_user()
    return jsonify({'message': 'Logged out successfully.'})

if __name__ == '__main__':
    app.run(debug=True)